import{_ as e,c as a,o as t,a3 as o}from"./chunks/framework.D5qxx6u8.js";const u=JSON.parse('{"title":"写在前面","description":"","frontmatter":{},"headers":[],"relativePath":"visualization/readme.md","filePath":"visualization/readme.md","lastUpdated":1768466808000}'),p={name:"visualization/readme.md"},r=o('<h1 id="写在前面" tabindex="-1">写在前面 <a class="header-anchor" href="#写在前面" aria-label="Permalink to &quot;写在前面&quot;">​</a></h1><p><strong>十年前端，从“增删改查”到“可视化之光”：我的第二个十年宣言</strong></p><p>2026 年 1 月 15 日，星期四。窗外冬意正浓，而我心中却燃起了一簇久违的火苗。</p><p>十年前，2016 年，我从一所普通二本院校毕业，怀揣着对代码世界的憧憬，踏入了前端开发的大门。那时的我，以为写几个漂亮的页面、调通几个接口，就是技术的全部。十年光阴如白驹过隙，回望这第一个十年，我确实完成了无数个需求，写了数不清的表单、列表、弹窗——增、删、改、查，循环往复。业务系统上线又迭代，项目交付又重构，我像一颗螺丝钉，牢牢拧在每一个项目的角落里，稳定、可靠，却也……平庸。</p><p>于是，在这个十年交汇的节点上，我郑重立下我的第二个十年目标：</p><blockquote><p><strong>我要成为一名真正的 WebGL 工程师，深耕 Web 可视化领域，用代码构建可交互、高性能、有美感的数据世界。</strong></p></blockquote><p>这不是一时兴起的幻想，而是一次深思熟虑的转身。我知道这条路并不轻松。WebGL 背后是线性代数、图形学、着色器语言（GLSL）、渲染管线、性能调优……这些曾让我望而却步的知识，如今成了我必须攀登的山峰。</p><p>我希望十年后的自己，不再是那个只会“实现 UI”的执行者，而是一个能用技术驱动产品、用可视化讲好数据故事的专家。在 AI 与大数据的时代，信息爆炸，但洞察稀缺。而可视化，正是将复杂转化为清晰的关键能力。我想成为那个“不可替代的牛马”——不是自嘲，而是自勉：即使做牛做马，也要做一头懂图形、会渲染、能创造价值的牛马。</p><p>为此，我制定了初步的学习路径：<a href="./plan">可视化工程师学习路线</a></p><p>我知道，转型之路注定孤独且漫长。但我已不再害怕“普通”。起点或许平凡，但方向决定终点。</p><p>2026，是我新十年的起点。</p><p>WebGL，我来了。</p><p>一位不甘平庸的前端程序员，于 2026 年初冬。</p>',13),s=[r];function n(_,i,c,d,l,m){return t(),a("div",null,s)}const f=e(p,[["render",n]]);export{u as __pageData,f as default};
